import './Header.css'

function Name() {
  return (
    <a href='#' className='text-center text-5xl'>
      harrison-e
    </a>
  );
}

function Links() {
  return (
    <div className='flex space-x-8 place-content-center'>
      <a href='https://www.github.com/harrison-e'>GitHub</a> 
      <a href='https://www.linkedin.com/in/harrison-eckert'>LinkedIn</a> 
      <a href='#'>Blog</a>
    </div>
  );
}

function Header() {
  return (
    <header className='text-stone-200 grid p-8 space-y-3 place-content-center'>
      <Name />
      <Links />
    </header>
  );
}

export default Header;
